text:
let {
    dragAndDropHooks,
    keyboardNavigationBehavior = 'arrow',
    layout = 'stack',
    orientation = 'vertical'
  } = props;

let {
    CollectionRoot,
    isVirtualized,
    layoutDelegate,
    dropTargetDelegate: ctxDropTargetDelegate
  } = useContext(CollectionRendererContext);

if (timeSegments.includes(state.granularity)) {
  end = granularityMap[state.granularity];
  timeSegments = timeSegments.slice(0, end);
}

let {
    isVirtualized,
    layoutDelegate,
    dropTargetDelegate: ctxDropTargetDelegate,
    CollectionRoot
  } = useContext(CollectionRendererContext);

let filteredCollection = useMemo(
  () => (filter ? collection.filter(filter) : collection),
  [collection, filter]
);

for (let cell of cells) {
  if (filterFn(cell.textValue, cell)) {
    let clone = this.clone();
    newCollection.addDescendants(clone, collection);
    return clone;
  }
}

export const TableColumnResizeStateContext = createContext<TableColumnResizeState<unknown> | null>(
  null
);

let [expandedKeys, setExpandedKeys] = useControlledState(
  props.expandedKeys ? new Set(props.expandedKeys) : undefined,
  props.defaultExpandedKeys ? new Set(props.defaultExpandedKeys) : new Set(),
  props.onExpandedChange
);

let {
    selectionMode = 'none',
    expandedKeys: propExpandedKeys,
    defaultExpandedKeys: propDefaultExpandedKeys,
    onExpandedChange,
    disabledBehavior = 'all'
  } = props;

if (!areSetsEqual(lastExpandedKeys, expandedKeys) || collection !== lastCollection) {
  setFlattenedCollection(collection.withExpandedKeys(lastExpandedKeys, expandedKeys));
  setLastCollection(collection);
  setLastExpandedKeys(expandedKeys);
}

let {
    inputRef,
    collectionRef,
    filter,
    disableAutoFocusFirst = false,
    disableVirtualFocus = false
  } = props;

useUpdateEffect(() => {
    if (selectedDateDescription) {
      announce(selectedDateDescription, 'polite', 4000);
    }
    // handle an update to the caption that describes the currently selected range, to announce the new value
  }, [selectedDateDescription]);

checkboxGroupData.set(state, {
  name,
  form,
  descriptionId: descriptionProps.id,
  errorMessageId: errorMessageProps.id,
  validationBehavior
});

if (filterFn(this.textValue, this)) {
  let clone = this.clone();
  newCollection.addDescendants(clone, collection);
  return clone;
}

if (!collection.getItem(element.node.key)) {
  for (let child of element) {
    this.addNode(child);
  }
}

if (node.node) {
  let collection = this.getMutableCollection();
  collection.removeNode(node.node.key);
}

let valueId = useValueId([
  state.selectionManager.selectedKeys,
  state.selectionManager.selectionMode
]);

for (let target of dropTargets.keys()) {
  if (nodeContains(target, element)) {
    return true;
  }
}

this.mutationObserver.observe(document.body, {
  subtree: true,
  attributes: true,
  attributeFilter: ['aria-hidden', 'inert']
});

if (node.children.size > 0) {
  for (let child of node.children) {
    yield* this.traverse(child);
  }
}

return {
  isInvalid: !input.validity.valid,
  validationDetails: getValidity(input),
  validationErrors: input.validationMessage ? [input.validationMessage] : []
};

let descriptionProps = useHighlightSelectionDescription({
  selectionManager: manager,
  hasItemActions: !!(onRowAction || onCellAction)
});

if (isVirtualized) {
  gridProps['aria-rowcount'] = state.collection.size;
  gridProps['aria-colcount'] = state.collection.columnCount;
}

listMap.set(state, {
  id,
  onAction,
  linkBehavior,
  keyboardNavigationBehavior,
  shouldSelectOnPressUp
});

let descriptionProps = useHighlightSelectionDescription({
  selectionManager: state.selectionManager,
  hasItemActions: !!onAction
});

return (
  (packageName && LocalizedStringDictionary.getGlobalDictionaryForPackage(packageName)) ||
  getCachedDictionary(strings)
);

if (!hasEventBeforeFocus && !hasBlurredWindowRecently) {
  currentModality = 'virtual';
  currentPointerType = 'virtual';
  triggerChangeHandlers('virtual', e);
}

Reflect.defineProperty(windowObject.HTMLElement.prototype, 'focus', {
  configurable: true,
  writable: true,
  value: function () {
    hasEventBeforeFocus = true;
    focus.apply(this, arguments as unknown as [options?: FocusOptions | undefined]);
  }
});

if (!(openLink as any).isOpening && isValidKey(e)) {
  currentModality = 'keyboard';
  currentPointerType = 'keyboard';
  triggerChangeHandlers('keyboard', e);
}
